def get_db():
    conn = sqlite3.connect(DB_PATH)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA journal_mode=WAL")
    conn.execute("PRAGMA foreign_keys=ON")
    return conn

def init_db():
    conn = get_db()
    conn.executescript("""
        CREATE TABLE IF NOT EXISTS channels (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            name TEXT NOT NULL,
            slug TEXT UNIQUE NOT NULL,
            description TEXT,
            color TEXT DEFAULT '#3b82f6',
            icon TEXT DEFAULT 'star',
            youtube_url TEXT DEFAULT '',
            tiktok_url TEXT DEFAULT '',
            instagram_url TEXT DEFAULT '',
            total_scripts INTEGER DEFAULT 0,
            created_at TEXT DEFAULT (datetime('now'))
        );
        CREATE TABLE IF NOT EXISTS scripts (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            channel_id INTEGER NOT NULL,
            title TEXT NOT NULL,
            slug TEXT NOT NULL,
            platform TEXT DEFAULT 'YouTube Long',
            duration_type TEXT DEFAULT '10min',
            hook TEXT,
            outline TEXT,
            full_script TEXT,
            broll_notes TEXT,
            thumbnail_concept TEXT,
            tags TEXT,
            description TEXT,
            cta TEXT,
            cross_post_platforms TEXT,
            status TEXT DEFAULT 'scripted',
            scheduled_date TEXT,
            published_url TEXT,
            views INTEGER DEFAULT 0,
            created_at TEXT DEFAULT (datetime('now')),
            FOREIGN KEY (channel_id) REFERENCES channels(id)
        );
        CREATE TABLE IF NOT EXISTS calendar (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            script_id INTEGER,
            platform TEXT,
            scheduled_date TEXT,
            scheduled_time TEXT,
            status TEXT DEFAULT 'scheduled',
            posted_at TEXT,
            FOREIGN KEY (script_id) REFERENCES scripts(id)
        );
        CREATE TABLE IF NOT EXISTS repurposed (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            original_script_id INTEGER,
            platform TEXT,
            title TEXT,
            content TEXT,
            status TEXT DEFAULT 'draft',
            created_at TEXT DEFAULT (datetime('now')),
            FOREIGN KEY (original_script_id) REFERENCES scripts(id)
        );
        CREATE TABLE IF NOT EXISTS performance (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            script_id INTEGER,
            platform TEXT,
            views INTEGER DEFAULT 0,
            likes INTEGER DEFAULT 0,
            comments INTEGER DEFAULT 0,
            shares INTEGER DEFAULT 0,
            updated_at TEXT DEFAULT (datetime('now')),
            FOREIGN KEY (script_id) REFERENCES scripts(id)
        );
        CREATE INDEX IF NOT EXISTS idx_scripts_channel ON scripts(channel_id);
        CREATE INDEX IF NOT EXISTS idx_scripts_status ON scripts(status);
        CREATE INDEX IF NOT EXISTS idx_scripts_slug ON scripts(slug);
        CREATE INDEX IF NOT EXISTS idx_calendar_date ON calendar(scheduled_date);
    """)
    conn.commit()
    conn.close()

def slugify(text):
    s = text.lower().strip()
    s = re.sub(r'[^\w\s-]', '', s)
    s = re.sub(r'[\s_]+', '-', s)
    s = re.sub(r'-+', '-', s)
    return s[:80]

def seed_data():
    conn = get_db()
    existing = conn.execute("SELECT COUNT(*) FROM channels").fetchone()[0]
    if existing > 0:
        conn.close()
        return
    for ch in CHANNELS:
        conn.execute(
            "INSERT INTO channels (name,slug,description,color,icon,youtube_url,tiktok_url,instagram_url) VALUES (?,?,?,?,?,?,?,?)",
            (ch["name"], ch["slug"], ch["description"], ch["color"], ch["icon"],
             ch.get("youtube_url",""), ch.get("tiktok_url",""), ch.get("instagram_url",""))
        )
    conn.commit()
    ch_map = {}
    for row in conn.execute("SELECT id, slug FROM channels").fetchall():
        ch_map[row["slug"]] = row["id"]

    base_date = datetime.now()
    script_count = 0
    for ch_slug, scripts in SCRIPT_LIBRARY.items():
        ch_id = ch_map.get(ch_slug)
        if not ch_id:
            continue
        for i, s in enumerate(scripts):
            sl = slugify(s["title"])
            sched = (base_date + timedelta(days=i)).strftime("%Y-%m-%d")
            conn.execute("""INSERT INTO scripts
                (channel_id,title,slug,platform,duration_type,hook,outline,full_script,
                 broll_notes,thumbnail_concept,tags,description,cta,cross_post_platforms,
                 status,scheduled_date)
                VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
                (ch_id, s["title"], sl, s["platform"], s["duration_type"],
                 s["hook"], s["outline"], s["full_script"],
                 s["broll_notes"], s["thumbnail_concept"], s["tags"],
                 s["description"], s["cta"], s["cross_post_platforms"],
                 "scripted", sched))
            script_count += 1
        conn.execute("UPDATE channels SET total_scripts=? WHERE id=?",
                     (len(scripts), ch_id))
    conn.commit()

    scripts_all = conn.execute("SELECT id, platform, scheduled_date FROM scripts ORDER BY scheduled_date").fetchall()
    time_slots = ["08:00","12:00","12:30","15:00","15:30","18:00","18:30"]
    slot_idx = 0
    for s in scripts_all:
        t = time_slots[slot_idx % len(time_slots)]
        slot_idx += 1
        conn.execute("INSERT INTO calendar (script_id,platform,scheduled_date,scheduled_time,status) VALUES (?,?,?,?,?)",
                     (s["id"], s["platform"], s["scheduled_date"], t, "scheduled"))
    conn.commit()
    conn.close()
    print(f"[SEED] Loaded {script_count} scripts across {len(ch_map)} channels")


def row_to_dict(row):
    if row is None:
        return None
    return dict(row)

def rows_to_list(rows):
    return [dict(r) for r in rows]

def get_stats():
    conn = get_db()
    total = conn.execute("SELECT COUNT(*) FROM scripts").fetchone()[0]
    published = conn.execute("SELECT COUNT(*) FROM scripts WHERE status='published'").fetchone()[0]
    today = datetime.now().strftime("%Y-%m-%d")
    today_count = conn.execute("SELECT COUNT(*) FROM calendar WHERE scheduled_date=?", (today,)).fetchone()[0]
    week_end = (datetime.now() + timedelta(days=7)).strftime("%Y-%m-%d")
    week_count = conn.execute("SELECT COUNT(*) FROM calendar WHERE scheduled_date BETWEEN ? AND ?", (today, week_end)).fetchone()[0]
    channels_active = conn.execute("SELECT COUNT(DISTINCT channel_id) FROM scripts").fetchone()[0]
    conn.close()
    return {
        "total_scripts": total,
        "published_this_month": published,
        "scheduled_this_week": week_count,
        "today_tasks": today_count,
        "content_velocity": round(total / max(30, 1), 1),
        "channels_active": channels_active,
    }


