async def handle_calendar(request):
    conn = get_db()
    today = datetime.now()
    start = today - timedelta(days=today.weekday())
    days_data = {}
    for i in range(28):
        d = (start + timedelta(days=i)).strftime("%Y-%m-%d")
        days_data[d] = []
    entries = rows_to_list(conn.execute(
        """SELECT cal.*, s.title, s.platform, c.color, c.slug as ch_slug, s.slug as sc_slug
        FROM calendar cal JOIN scripts s ON cal.script_id=s.id JOIN channels c ON s.channel_id=c.id
        WHERE cal.scheduled_date BETWEEN ? AND ?
        ORDER BY cal.scheduled_time""",
        (start.strftime("%Y-%m-%d"), (start+timedelta(days=28)).strftime("%Y-%m-%d"))).fetchall())
    conn.close()
    for e in entries:
        d = e["scheduled_date"]
        if d in days_data:
            days_data[d].append(e)

    headers = ""
    for d in ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"]:
        headers += '<div class="cal-header">' + d + '</div>'
    cells = ""
    for i in range(28):
        d = (start + timedelta(days=i)).strftime("%Y-%m-%d")
        day_num = (start + timedelta(days=i)).day
        is_today = d == today.strftime("%Y-%m-%d")
        border = "border:2px solid #3b82f6" if is_today else ""
        events = ""
        for ev in days_data.get(d, [])[:4]:
            t_str = (ev.get("scheduled_time") or "")[:5]
            t_title = (ev.get("title") or "")[:20]
            events += '<div class="event" style="background:' + ev["color"] + '" title="' + ev.get("title","") + '">' + t_str + ' ' + t_title + '</div>'
        overflow = len(days_data.get(d,[])) - 4
        if overflow > 0:
            events += '<div style="color:#94a3b8;font-size:0.7em">+' + str(overflow) + ' more</div>'
        cells += '<div class="cal-day" style="' + border + '"><div class="date">' + str(day_num) + '</div>' + events + '</div>'

    body = '<h2 style="margin-bottom:20px">Content Calendar (4 Weeks)</h2><div class="calendar-grid">' + headers + cells + '</div>'
    return web.Response(text=html_page("Calendar", body), content_type="text/html")


