async def handle_week(request):
    conn = get_db()
    today = datetime.now()
    week_end = today + timedelta(days=7)
    tasks = rows_to_list(conn.execute(
        """SELECT cal.*, s.title, s.platform, s.duration_type, c.name as ch_name, c.color, c.slug as ch_slug, s.slug as sc_slug
        FROM calendar cal JOIN scripts s ON cal.script_id=s.id JOIN channels c ON s.channel_id=c.id
        WHERE cal.scheduled_date BETWEEN ? AND ? ORDER BY cal.scheduled_date, cal.scheduled_time""",
        (today.strftime("%Y-%m-%d"), week_end.strftime("%Y-%m-%d"))).fetchall())
    conn.close()
    by_date = {}
    for t in tasks:
        by_date.setdefault(t["scheduled_date"], []).append(t)

    body = '<h2 style="margin-bottom:20px">This Week\'s Content Plan</h2><p style="color:#94a3b8;margin-bottom:20px">' + str(len(tasks)) + ' items across 7 days</p>'
    for d in sorted(by_date.keys()):
        body += '<h3 style="color:#60a5fa;margin:20px 0 10px">' + d + ' (' + str(len(by_date[d])) + ' items)</h3>'
        for t in by_date[d]:
            t_time = (t.get("scheduled_time") or "")[:5]
            body += (
                '<div class="script-item" style="border-left:3px solid ' + t["color"] + '">'
                '<div style="display:flex;justify-content:space-between">'
                '<h4><a href="/channel/' + t["ch_slug"] + '/' + t["sc_slug"] + '">' + t_time + ' ' + t["title"] + '</a></h4>'
                '<span class="badge" style="background:' + t["color"] + '30;color:' + t["color"] + '">' + t["ch_name"] + '</span>'
                '</div></div>'
            )
    if not by_date:
        body += '<p style="color:#475569;padding:40px;text-align:center">No content scheduled this week.</p>'
    return web.Response(text=html_page("This Week", body), content_type="text/html")


async def handle_repurpose(request):
    sc_slug = request.match_info["video_slug"]
    conn = get_db()
    script = row_to_dict(conn.execute(
        "SELECT s.*, c.name as ch_name, c.color, c.slug as ch_slug FROM scripts s JOIN channels c ON s.channel_id=c.id WHERE s.slug=?",
        (sc_slug,)).fetchone())
    conn.close()
    if not script:
        return web.Response(text="Script not found", status=404)

    hook = script.get("hook","")
    outline = script.get("outline","")
    full = script.get("full_script","")
    platforms = [
        ("YouTube Shorts", "60-second version: " + hook[:100] + " [Key points] Follow for more!", "#ec4899"),
        ("TikTok", "Hook: " + hook[:80] + "... Quick tips format. Trending audio.", "#ff0050"),
        ("Instagram Reel", "Visual storytelling. " + hook[:60] + " Strong visual opener.", "#e1306c"),
        ("Blog Post", "# " + script["title"] + "\n\n" + full[:400] + "...\n\n[Expanded with SEO headers]", "#f97316"),
        ("Tweet Thread", "1/ " + hook[:200] + "\n\n2/ [Key insight]\n\n3/ [Data point]\n\n4/ hivecore.app", "#1da1f2"),
        ("Email Newsletter", "Subject: " + script["title"] + "\n\n" + hook + "\n\n[Condensed body]\n\nCTA: Watch", "#10b981"),
        ("Podcast Clip", "2-3 min excerpt: " + outline[:200] + "\nAdd intro jingle.", "#6366f1"),
    ]
    cards = ""
    for name, content, color in platforms:
        safe = content.replace("<","&lt;").replace(">","&gt;")[:300]
        cards += (
            '<div class="repurpose-card" style="border-top:3px solid ' + color + '">'
            '<h4 style="color:' + color + '">' + name + '</h4>'
            '<p style="white-space:pre-wrap;font-size:0.85em">' + safe + '</p>'
            '</div>'
        )
    body = (
        '<a href="/channel/' + script["ch_slug"] + '/' + script["slug"] + '" class="btn btn-secondary" style="margin-bottom:20px;display:inline-block">Back to Script</a>'
        '<h2 style="margin-bottom:10px">Repurpose: ' + script["title"] + '</h2>'
        '<p style="color:#94a3b8;margin-bottom:25px">One piece of content becomes 7 assets across every platform</p>'
        '<div class="repurpose-grid">' + cards + '</div>'
    )
    return web.Response(text=html_page("Repurpose", body), content_type="text/html")


