async def api_generate(request):
    data = await request.json()
    channel_slug = data.get("channel","hive-ai")
    topic = data.get("topic","AI Tips")
    platform = data.get("platform","YouTube Long")
    duration = data.get("duration","10min")
    conn = get_db()
    ch = row_to_dict(conn.execute("SELECT * FROM channels WHERE slug=?", (channel_slug,)).fetchone())
    if not ch:
        conn.close()
        return web.json_response({"error": "Channel not found"}, status=404)
    slug = slugify(topic)
    hook = "Here is everything you need to know about " + topic + ". Most people get this wrong."
    outline = "1. Introduction to " + topic + "\n2. Key concepts\n3. Practical examples\n4. Common mistakes\n5. Action steps"
    script_text = ("Today we are diving deep into " + topic + ". This is something I get asked about constantly "
                   "and most of the advice out there is completely wrong. Let me share what actually works based on "
                   "real experience building AI systems every single day.\n\n"
                   "[Generated script for " + topic + " - expand with domain expertise]\n\n"
                   "If you found this valuable, subscribe for more. Visit hivecore.app to see these systems in action.")
    conn.execute("""INSERT INTO scripts (channel_id,title,slug,platform,duration_type,hook,outline,full_script,status,scheduled_date)
        VALUES (?,?,?,?,?,?,?,?,?,?)""",
        (ch["id"], topic, slug, platform, duration, hook, outline, script_text, "idea", datetime.now().strftime("%Y-%m-%d")))
    conn.execute("UPDATE channels SET total_scripts = total_scripts + 1 WHERE id=?", (ch["id"],))
    conn.commit()
    new_id = conn.execute("SELECT last_insert_rowid()").fetchone()[0]
    conn.close()
    return web.json_response({"success": True, "script_id": new_id, "title": topic, "channel": channel_slug})

