async def api_repurpose(request):
    sid = request.match_info["id"]
    conn = get_db()
    script = row_to_dict(conn.execute("SELECT * FROM scripts WHERE id=?", (sid,)).fetchone())
    if not script:
        conn.close()
        return web.json_response({"error":"Script not found"}, status=404)
    platforms = ["YouTube Short","TikTok","Instagram Reel","Blog Post","Tweet Thread","Email Newsletter","Podcast Clip"]
    created = []
    for p in platforms:
        title = "[" + p + "] " + script["title"]
        content = "Repurposed from: " + script["title"] + "\nPlatform: " + p + "\nHook: " + (script.get("hook") or "") + "\n\n[Auto-generated " + p + " version]"
        conn.execute("INSERT INTO repurposed (original_script_id,platform,title,content) VALUES (?,?,?,?)",
                     (sid, p, title, content))
        created.append({"platform": p, "title": title})
    conn.commit()
    conn.close()
    return web.json_response({"success": True, "repurposed": created})

