def create_app():
    app = web.Application()
    app.router.add_get("/", handle_dashboard)
    app.router.add_get("/channel/{channel_slug}", handle_channel)
    app.router.add_get("/channel/{channel_slug}/{video_slug}", handle_script_detail)
    app.router.add_get("/pipeline", handle_pipeline)
    app.router.add_get("/calendar", handle_calendar)
    app.router.add_get("/schedule/today", handle_today)
    app.router.add_get("/schedule/week", handle_week)
    app.router.add_get("/repurpose/{video_slug}", handle_repurpose)
    app.router.add_get("/api/channels", api_channels)
    app.router.add_get("/api/channel/{slug}/scripts", api_channel_scripts)
    app.router.add_get("/api/script/{id}", api_script_detail)
    app.router.add_post("/api/generate", api_generate)
    app.router.add_get("/api/calendar", api_calendar)
    app.router.add_get("/api/today", api_today)
    app.router.add_get("/api/stats", api_stats)
    app.router.add_post("/api/repurpose/{id}", api_repurpose)
    app.router.add_get("/health", handle_health)
    return app

